-- Ghana Tertiary UniConnect Dataset - part 3
-- Run parts sequentially in Supabase SQL Editor.

update public.faculties set source_id = coalesce(source_id, 'cug_business_and_management_studies') where source_id = 'cug_business_and_management_studies' or (name = 'Business and Management Studies' and university_id = (select id from public.universities where source_id = 'cug'));
insert into public.faculties (source_id, university_id, name) select 'cug_computing_and_information_technology', u.id, 'Computing and Information Technology' from public.universities u where u.source_id = 'cug' and not exists (select 1 from public.faculties where source_id = 'cug_computing_and_information_technology' or (university_id = u.id and name = 'Computing and Information Technology'));
